import { Kernel } from '@microsoft/semantic-kernel';
import { HandlebarsPlanner } from '@microsoft/semantic-kernel/planner-handlebars';

const kernel = Kernel.create();

function validatePlan(plan: Plan) {
  const functions = kernel.functions.listFunctions();
  const functionNames = functions.map(f => f.name);

  for (const step of plan.steps) {
    if (!functionNames.includes(step.function.name)) {
      console.error(`Invalid plan step: ${step.function.name} not found`);
      return false;
    }
  }
  return true;
}

const planner = new HandlebarsPlanner(kernel);
const plan = await planner.createPlan('process order');
validatePlan(plan);
